--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -430,11 +430,81 @@
 export function drawRoom(
   ctx: CanvasRenderingContext2D,
   type: CharacterType,
   x: number, y: number, w: number, h: number, frame: number,
 ) {
-  const roomBg: Record<CharacterType, string> = {
-    king: '#1e0e2a', nobility: '#14203a', knight: '#142030', squire: '#142014',
-    healer: '#141830', sentinel: '#0e1424', scribe: '#201808', judge: '#14101a', blacksmith: '#181008',
-  };
-  ctx.fillStyle = roomBg[type];
+  const roomBg: Record<CharacterType, string> = {
+    king: '#1e0e2a', nobility: '#14203a', knight: '#142030', squire: '#142014',
+    healer: '#141830', sentinel: '#0e1424', scribe: '#201808', judge: '#14101a', blacksmith: '#181008',
+  };
+  ctx.fillStyle = roomBg[type];
+
+  // Draw floor background
+  ctx.fillRect(x, y, w, h);
+
+  // Wall parameters
+  const wallHeight = 24;
+  const brickWidth = 16;
+  const brickHeight = 8;
+  const mortarThickness = 1;
+  const wallTop = y + h - wallHeight;
+
+  // Base wall color
+  const baseWallColor = '#7a4a3c';
+
+  // Helper: lighten or darken hex color by amount (-1 to 1)
+  function shadeColor(color: string, percent: number) {
+    const f = parseInt(color.slice(1),16);
+    const t = percent < 0 ? 0 : 255;
+    const p = Math.abs(percent);
+    const R = f >> 16;
+    const G = (f >> 8) & 0x00FF;
+    const B = f & 0x0000FF;
+    const r = Math.round((t - R) * p) + R;
+    const g = Math.round((t - G) * p) + G;
+    const b = Math.round((t - B) * p) + B;
+    return `rgb(${r},${g},${b})`;
+  }
+
+  // Draw bricks with mortar lines and shading
+  for (let row = 0; row < Math.ceil(wallHeight / brickHeight); row++) {
+    const yBrick = wallTop + row * brickHeight;
+    const offset = (row % 2) * (brickWidth / 2);
+    for (let col = -1; col < Math.ceil(w / brickWidth) + 1; col++) {
+      const xBrick = x + col * brickWidth + offset;
+      if (xBrick + brickWidth < x || xBrick > x + w) continue;
+
+      // Random color variation ±10% shade
+      const variation = (Math.random() * 0.2) - 0.1;
+      let brickColor = shadeColor(baseWallColor, variation);
+
+      // Shadow gradient: darker at bottom, lighter at top
+      const shadowFactor = (row + 1) / (wallHeight / brickHeight);
+      brickColor = shadeColor(brickColor, -0.3 * shadowFactor + 0.15);
+
+      ctx.fillStyle = brickColor;
+      ctx.fillRect(xBrick, yBrick, brickWidth - mortarThickness, brickHeight - mortarThickness);
+
+      // Mortar lines: 1px lighter lines horizontally and vertically in brick pattern
+      ctx.strokeStyle = 'rgba(255,255,255,0.15)';
+      ctx.lineWidth = mortarThickness;
+      ctx.beginPath();
+      // Horizontal mortar line at bottom of brick
+      ctx.moveTo(xBrick, yBrick + brickHeight - mortarThickness / 2);
+      ctx.lineTo(xBrick + brickWidth, yBrick + brickHeight - mortarThickness / 2);
+      // Vertical mortar line at left edge of brick
+      ctx.moveTo(xBrick + mortarThickness / 2, yBrick);
+      ctx.lineTo(xBrick + mortarThickness / 2, yBrick + brickHeight);
+      ctx.stroke();
+    }
+  }
+
+  // Subtle highlight line at top edge of wall
+  const grad = ctx.createLinearGradient(x, wallTop, x, wallTop + 4);
+  grad.addColorStop(0, 'rgba(255,255,255,0.15)');
+  grad.addColorStop(1, 'rgba(255,255,255,0)');
+  ctx.fillStyle = grad;
+  ctx.fillRect(x, wallTop, w, 4);
+}
+
